import{c as a,Q as s,j as n,m as t}from"./chunks/framework.iD28w_5a.js";const u=JSON.parse('{"title":"028e-activate-init-thread-2 · Init 线程","description":"","frontmatter":{"title":"028e-activate-init-thread-2 · Init 线程"},"headers":[],"relativePath":"hands-on/028e-activate-init-thread-2.md","filePath":"hands-on/028e-activate-init-thread-2.md","lastUpdated":1779686691000}'),c={name:"hands-on/028e-activate-init-thread-2.md"};function d(o,e,i,r,p,l){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="init-线程实现与用户态启动" tabindex="-1">init 线程实现与用户态启动 <a class="header-anchor" href="#init-线程实现与用户态启动" aria-label="Permalink to &quot;init 线程实现与用户态启动&quot;">​</a></h1><blockquote><p>标签：init thread, ext2 mount, VFS, launch_first_user, placement new, singleton 前置：<a href="./028e-activate-init-thread-1">028e-1 从 kernel_main 到 init 线程</a></p></blockquote><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>上一章我们把 <code>kernel_main()</code> 拆成了「早期初始化 + 调度器启动 + idle 循环」的三段式结构，创建了 init 线程的骨架。现在我们要填充 init 线程的实际内容——ext2 挂载、VFS 注册、以及第一个用户态程序的启动。这一步看起来只是把代码从 <code>kernel_main()</code> 搬到 <code>kernel_init_thread()</code> 里，但实际上会暴露出两个非常隐蔽的 bug：一个是 <code>launch_first_user()</code> 里的 <code>static Task shell_task{}</code> 伪造问题，另一个是 <code>AddressSpace</code> 析构器导致的 <code>__dso_handle</code> 链接错误。</p><p>完成本章后，我们的内核就能以一个正规的、调度器管理的 init 内核线程为起点，经过 ext2 挂载和 VFS 注册，最终在 Ring 3 启动 shell。整个链条中没有伪造的 Task，没有绕过调度器的 hack，一切都是干干净净的。</p><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="shell-task-伪造问题" tabindex="-1">shell_task 伪造问题 <a class="header-anchor" href="#shell-task-伪造问题" aria-label="Permalink to &quot;shell_task 伪造问题&quot;">​</a></h3><p>在 028d 之前的实现中，<code>launch_first_user()</code> 函数里有这么一行：声明一个 <code>static Task shell_task{}</code>，然后把它的 cwd 设成 &quot;/&quot;，state 设成 Running，再通过 <code>Scheduler::set_current(&amp;shell_task)</code> 把它塞进调度器的当前任务指针。这个 Task 是零初始化的——这意味着它的内核栈指针是 NULL，tid 是 0，CPU 上下文全是零，它根本不在任何运行队列里。</p><p>为什么之前没出问题呢？因为之前的启动流程是线性的——shell 启动之后就不会再回到内核态了（至少在早期 tag 里是这样）。但当我们的 shell 开始使用 <code>sys_exit</code> 系统调用时，问题就来了：<code>sys_exit</code> 会调用 <code>Scheduler::current()</code> 拿到这个伪造的 Task，标记它为 Dead，然后 yield。调度器发现当前 Task 被标记为 Dead，就会从运行队列中挑选下一个——但这个伪造的 Task 从来就没在运行队列里，所以 dequeue 操作会在队列中找不到它。如果调度器后来试图切回这个 Task（比如中断返回），它会发现 CPU 上下文全是零，RIP 跳到地址 0x0，直接 triple fault。</p><p>真正的修复方案很简单：不用伪造 Task，直接使用调度器已经管理的 init 线程 Task。init 线程是由 <code>TaskBuilder::build()</code> 正确创建的——有真实的内核栈、有效的 tid、完整的 CPU 上下文、在运行队列中。我们只需要在 <code>launch_first_user()</code> 里获取当前 Task，然后更新它的 <code>addr_space</code> 和 <code>cwd</code> 字段就行了。</p><h3 id="placement-new-与-dso-handle" tabindex="-1">Placement New 与 <code>__dso_handle</code> <a class="header-anchor" href="#placement-new-与-dso-handle" aria-label="Permalink to &quot;Placement New 与 \`__dso_handle\`&quot;">​</a></h3><p><code>launch_first_user()</code> 需要创建一个 <code>AddressSpace</code> 对象来管理用户态的页表。在 028d 之前的代码中，这个对象是直接在栈上声明的——<code>AddressSpace user_space;</code>。这在编译时没有问题，但当 <code>AddressSpace</code> 类有了析构器之后，编译器会为栈上的对象注册一个 atexit 回调（通过 <code>__dso_handle</code>），用于在作用域结束时调用析构器。问题是我们的内核没有链接标准库，也没有 <code>__dso_handle</code> 的定义，所以链接阶段直接报 undefined reference 错误。</p><p>解决方案是 placement new——在一个 static 字节数组上手动构造 <code>AddressSpace</code> 对象。因为字节数组本身没有析构器，编译器不会注册 atexit 回调。<code>AddressSpace</code> 对象虽然在 static 存储上构造了，但我们永远不会显式调用它的析构器——这个对象的生命周期和内核一样长，内核关机时不需要释放它。</p><h3 id="ahci-单例模式" tabindex="-1">AHCI 单例模式 <a class="header-anchor" href="#ahci-单例模式" aria-label="Permalink to &quot;AHCI 单例模式&quot;">​</a></h3><p><code>init.cpp</code> 被编译进 <code>big_kernel_common</code> 库（一个 OBJECT library），而 AHCI 实例 <code>ahci</code> 是 <code>kernel_main()</code> 中的局部变量，定义在 <code>main.cpp</code> 中（<code>big_kernel</code> 可执行文件）。当链接测试二进制时，只链接 <code>big_kernel_common</code> 而不链接 <code>big_kernel</code>，所以 <code>init.cpp</code> 里对 AHCI 的引用就会找不到。</p><p>解决方案是给 AHCI 类添加静态的 <code>instance()</code> 和 <code>set_instance()</code> 方法——一个典型的 Meyer&#39;s Singleton 变体（虽然不是线程安全的，但我们的内核初始化是单线程的，所以没关系）。<code>kernel_main()</code> 在 AHCI 初始化完成后调用 <code>set_instance(&amp;ahci)</code>，init 线程通过 <code>AHCI::instance()</code> 获取引用。</p><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-实现-init-线程的完整流程" tabindex="-1">Step 1: 实现 init 线程的完整流程 <a class="header-anchor" href="#step-1-实现-init-线程的完整流程" aria-label="Permalink to &quot;Step 1: 实现 init 线程的完整流程&quot;">​</a></h3><p><strong>目标</strong>: 在 <code>kernel/proc/init.cpp</code> 中实现 init 线程的完整工作流：ext2 挂载、VFS 注册、用户态启动。</p><p><strong>设计思路</strong>: init 线程的执行序列是固定的：首先通过 <code>Scheduler::current()</code> 获取自己的 Task 信息并打印日志；然后创建 ext2 实例并挂载——ext2 的构造函数需要 AHCI 引用（通过 <code>AHCI::instance()</code> 获取）和端口号；接着初始化 VFS 挂载表，把 ext2 注册到根路径 &quot;/&quot;；最后调用 <code>launch_first_user()</code> 启动第一个用户态程序。</p><p>ext2 实例需要声明为 <code>static</code>——因为它必须在整个内核生命周期中存活。如果声明为普通局部变量，函数返回后它就会被销毁（如果它有析构器的话），而 shell 和其他进程还需要通过 VFS 访问 ext2。</p><p><strong>实现约束</strong>: init 线程函数签名为 <code>void kernel_init_thread()</code>，无参数无返回值。包含必要的头文件：AHCI、ext2、VFS、usermode、scheduler、sync。调用 <code>Scheduler::exit_current()</code> 结束线程。</p><p><strong>踩坑预警</strong>: 如果你忘了在 <code>kernel_main()</code> 中调用 <code>AHCI::set_instance()</code>，init 线程里的 <code>AHCI::instance()</code> 会返回空指针，然后 ext2 构造函数解引用空指针直接 triple fault。确保 <code>set_instance()</code> 在 <code>Scheduler::init()</code> 之前被调用。</p><p><strong>验证</strong>: 运行内核，串口输出应显示：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[INIT] kernel_init started tid=2</span></span>
<span class="line"><span>[INIT] ===== Milestone 028: ext2 Filesystem =====</span></span>
<span class="line"><span>[EXT2] Superblock: magic=0xef53 ...</span></span>
<span class="line"><span>[INIT] ===== Milestone 027: VFS =====</span></span>
<span class="line"><span>[VFS] ext2 mounted at /</span></span>
<span class="line"><span>[INIT] ===== Milestone 023: Syscall from Ring 3 =====</span></span>
<span class="line"><span>[USER] Setting up first user-mode program...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="step-2-修复-launch-first-user-的-task-问题" tabindex="-1">Step 2: 修复 launch_first_user 的 Task 问题 <a class="header-anchor" href="#step-2-修复-launch-first-user-的-task-问题" aria-label="Permalink to &quot;Step 2: 修复 launch_first_user 的 Task 问题&quot;">​</a></h3><p><strong>目标</strong>: 移除 <code>usermode.cpp</code> 中伪造的 <code>static Task shell_task{}</code>，改为使用调度器管理的当前 Task。</p><p><strong>设计思路</strong>: init 线程在调用 <code>launch_first_user()</code> 时，<code>Scheduler::current()</code> 返回的就是 init 线程的 Task——一个有完整内核栈、有效 tid、在运行队列中的正规 Task。我们只需要更新它的两个字段：<code>addr_space</code> 指向新创建的用户态地址空间，<code>cwd</code> 设为 &quot;/&quot;。</p><p><strong>实现约束</strong>: 获取当前 Task 后检查是否为空（防御性编程），然后更新 <code>addr_space</code> 和 <code>cwd</code>，再调用 <code>set_current()</code> 通知调度器 Task 已更新。不再需要手动设置 <code>state</code>——Task 已经是 Running 状态了。</p><p><strong>踩坑预警</strong>: 千万不要删除 <code>Scheduler::set_current()</code> 调用。虽然看起来好像只是更新了一个指针，但调度器内部的 <code>g_per_cpu.current</code> 也需要同步更新，否则后续的系统调用会拿到过期的 Task 指针。</p><p><strong>验证</strong>: shell 启动后尝试输入命令，如果 shell 能正常执行 <code>sys_exit</code>（比如输入 exit），不应该看到 kernel panic 或者 triple fault。</p><h3 id="step-3-addressspace-的-placement-new" tabindex="-1">Step 3: AddressSpace 的 Placement New <a class="header-anchor" href="#step-3-addressspace-的-placement-new" aria-label="Permalink to &quot;Step 3: AddressSpace 的 Placement New&quot;">​</a></h3><p><strong>目标</strong>: 将栈上分配的 <code>AddressSpace</code> 改为 placement new 在 static buffer 上构造。</p><p><strong>设计思路</strong>: 声明一个 <code>alignas(alignof(AddressSpace)) static uint8_t storage[sizeof(AddressSpace)]</code> 的字节数组作为存储空间，然后用 placement new 在这个数组上构造 AddressSpace 对象。之后所有对 <code>user_space</code> 的成员访问都改成指针访问（<code>user_space-&gt;map()</code> 而不是 <code>user_space.map()</code>）。</p><p><strong>实现约束</strong>: 需要包含 <code>&lt;new&gt;</code> 头文件来使用 placement new。字节数组的对齐必须等于 <code>alignof(AddressSpace)</code>，否则可能是未定义行为。整个文件中所有对 <code>user_space</code> 的点号访问都要改成箭头访问。</p><p><strong>验证</strong>: 编译通过，不出现 <code>__dso_handle</code> 的 undefined reference 错误。运行时用户态地址空间正常激活。</p><h3 id="step-4-ahci-单例封装" tabindex="-1">Step 4: AHCI 单例封装 <a class="header-anchor" href="#step-4-ahci-单例封装" aria-label="Permalink to &quot;Step 4: AHCI 单例封装&quot;">​</a></h3><p><strong>目标</strong>: 在 AHCI 类中添加静态的 <code>instance()</code>、<code>set_instance()</code> 方法和静态成员指针。</p><p><strong>设计思路</strong>: 在 AHCI 类中声明一个 <code>static AHCI* s_instance_</code> 指针，初始值为 nullptr。<code>set_instance()</code> 设置这个指针，<code>instance()</code> 返回解引用后的引用。在 <code>.cpp</code> 文件中定义静态成员并实现这两个方法。</p><p><strong>实现约束</strong>: 静态成员指针需要在 <code>.cpp</code> 文件中定义（不能在头文件中 inline 定义，否则多个翻译单元会各自有一份副本）。<code>instance()</code> 如果在 <code>set_instance()</code> 之前被调用会解引用空指针——但我们不检查这个，因为这是一个内核内部的 API，调用顺序由开发者保证。</p><p><strong>验证</strong>: 编译通过，包括测试二进制（它只链接 <code>big_kernel_common</code>）。运行时 init 线程能正确获取 AHCI 实例并完成 ext2 挂载。</p><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><p>完整的构建和运行命令：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd build &amp;&amp; cmake .. &amp;&amp; make -j$(nproc)</span></span>
<span class="line"><span>./run.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>检查串口输出的关键日志序列：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[INIT] kernel_init started tid=2</span></span>
<span class="line"><span>[INIT] ===== Milestone 028: ext2 Filesystem =====</span></span>
<span class="line"><span>[EXT2] Superblock: magic=0xef53 rev=1.0 ...</span></span>
<span class="line"><span>[INIT] ===== Milestone 027: VFS =====</span></span>
<span class="line"><span>[VFS] ext2 mounted at /</span></span>
<span class="line"><span>[INIT] ===== Milestone 023: Syscall from Ring 3 =====</span></span>
<span class="line"><span>[USER] Setting up first user-mode program...</span></span>
<span class="line"><span>[USER] User address space activated</span></span>
<span class="line"><span>[USER] Jumping to Ring 3</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><p><strong>init 线程中 ext2 mount 失败</strong>：如果看到 <code>[INIT] ext2 mount failed!</code>，首先检查 AHCI Port 1 是否检测到设备（在 AHCI init 阶段应该看到 <code>SSTS=0x113 DET=3</code>）。如果 init 线程中 Port 1 的 SSTS 变成了 0x0，那说明 MMIO 映射被覆盖了——这是下一章要讨论的核心问题。</p><p><strong><code>__dso_handle</code> 链接错误</strong>：如果链接阶段报 <code>undefined reference to &#39;__dso_handle&#39;</code>，说明某个有析构器的对象被声明为栈变量或全局变量。检查 <code>launch_first_user()</code> 中的 <code>AddressSpace</code> 是否改成了 placement new。</p><p><strong>shell 启动后立刻崩溃</strong>：如果 shell 的 Ring 3 入口执行后立刻触发异常，检查 <code>current-&gt;addr_space</code> 是否正确设置了——如果 <code>launch_first_user()</code> 里的 <code>Scheduler::current()</code> 返回了 nullptr，addr_space 就不会被设置，用户态页表就没有被正确激活。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>说明</th></tr></thead><tbody><tr><td>shell_task 伪造</td><td>零初始化的假 Task，没有内核栈，不在运行队列</td></tr><tr><td>调度器管理的 Task</td><td>由 TaskBuilder 正确创建的 Task，有完整生命周期</td></tr><tr><td>Placement new</td><td>在预分配的 static buffer 上构造对象，避免析构器链接问题</td></tr><tr><td>AHCI 单例</td><td><code>instance()/set_instance()</code> 解决跨翻译单元访问</td></tr><tr><td><code>Scheduler::exit_current()</code></td><td>init 线程完成后的正常退出方式</td></tr></tbody></table><p>到这里，init 线程的核心实现就完成了。但在实际测试中，你大概率会遇到一个非常诡异的问题——ext2 挂载在 AHCI init 阶段显示设备正常，但 init 线程中去读就超时了。这就是我们下一章要拆解的 MMIO 地址冲突问题，说实话这个 bug 真的坑了我半天。</p>`,53)])])}const _=a(c,[["render",d]]);export{u as __pageData,_ as default};
